          "type": "string",
          "minLength": 1
        },
        "required_capabilities": {
          "type": "array",
          "items": {
            "type": "string",
            "minLength": 1
          }
        },
        "acceptance_criteria": {
          "type": "array",
          "items": {}
        },
        "boundary": {
          "type": "object"
        },
        "priority": {
          "type": "string",
          "minLength": 1
        },
        "evidence_refs": {
          "type": "array",
          "items": {
            "type": "object"
          }
        }
